--
-- Name: prevent_parent_activation(); Type: FUNCTION; Schema: authentification; Owner: postgres
--

CREATE FUNCTION authentification.prevent_parent_activation() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    has_relation BOOLEAN := FALSE;
    has_ape BOOLEAN := FALSE;
    parent_id UUID;
BEGIN
    IF (NEW.role_actuel = 'PARENT' AND NEW.est_actif = TRUE) THEN
        -- vĂ”Ă‡Ăœrifier relation parent -> enfant
        SELECT EXISTS (SELECT 1 FROM vie_scolaire.relations_parents_eleves r WHERE r.id_parent = NEW.id_user) INTO has_relation;

        -- vĂ”Ă‡Ăœrifier s'il est membre du bureau APE (via profils_parents -> bureau_direction)
        SELECT EXISTS (
            SELECT 1 FROM gestion_ape.bureau_direction b
            WHERE b.id_parent = (
                SELECT p.id_parent FROM gestion_ape.profils_parents p WHERE p.id_user = NEW.id_user LIMIT 1
            )
        ) INTO has_ape;

        IF NOT (has_relation OR has_ape) THEN
            RAISE EXCEPTION 'Activation refusĂ”Ă‡Ăœe: un parent doit avoir au moins un enfant liĂ”Ă‡Ăœ ou â•¦Ă¥tre membre du bureau APE.';
        END IF;
    END IF;
    RETURN NEW;
END;
$$;


