--
-- Name: audit_notes(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.audit_notes() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    user_id UUID;
BEGIN
    BEGIN
        user_id := current_setting('app.current_user_id', true)::UUID;
    EXCEPTION WHEN OTHERS THEN
        user_id := NULL;
    END;
    
    VALUES (
        user_id,
        TG_OP,
        'notes_evaluations',
        NEW.id_evaluation::TEXT,
        CASE WHEN TG_OP = 'UPDATE' THEN row_to_json(OLD) ELSE NULL END,
        row_to_json(NEW)
    );
    
    RETURN NEW;
END;
$$;


