--
-- Name: vue_utilisateurs_simple; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vue_utilisateurs_simple AS
 SELECT c.code_unique AS matricule,
    c.nom,
    c.prenom,
    c.email,
    c.role_actuel AS role,
        CASE
            WHEN (c.mot_de_passe = 'NON_ACTIVE'::text) THEN 'â”¬Ă€ activer'::text
            ELSE 'Actif'::text
        END AS statut,
    to_char(c.date_creation, 'DD/MM/YYYY'::text) AS date_inscription,
        CASE
            WHEN (c.role_actuel = ANY (ARRAY['DIRECTION'::public.role_utilisateur, 'SURVEILLANT'::public.role_utilisateur])) THEN adm.poste_occupe
            WHEN (c.role_actuel = 'PROFESSEUR'::public.role_utilisateur) THEN p.specialite
            WHEN (c.role_actuel = 'ELEVE'::public.role_utilisateur) THEN pe.classe_actuelle
            ELSE NULL::character varying
        END AS info
   FROM (((authentification.comptes c
     LEFT JOIN authentification.profils_administratifs adm ON ((c.id_user = adm.id_user)))
     LEFT JOIN pedagogie.profils_profs p ON ((c.id_user = p.id_user)))
     LEFT JOIN vie_scolaire.profils_eleves pe ON ((c.id_user = pe.id_user)))
  WHERE (c.role_actuel = ANY (ARRAY['DIRECTION'::public.role_utilisateur, 'SURVEILLANT'::public.role_utilisateur, 'PROFESSEUR'::public.role_utilisateur, 'ELEVE'::public.role_utilisateur, 'PARENT'::public.role_utilisateur, 'ALUMNI'::public.role_utilisateur]));


ALTER VIEW public.vue_utilisateurs_simple OWNER TO postgres;

--
-- Name: vue_utilisateurs_unifiee; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vue_utilisateurs_unifiee AS
 SELECT c.code_unique AS matricule,
    c.nom,
    c.prenom,
    c.email,
    c.telephone,
    c.role_actuel AS role,
        CASE
            WHEN (c.mot_de_passe = 'NON_ACTIVE'::text) THEN '?? â”¬Ă€ activer'::text
            WHEN (c.mot_de_passe IS NULL) THEN '? Sans mot de passe'::text
            ELSE '?? Actif'::text
        END AS statut_compte,
    to_char(c.date_creation, 'DD/MM/YYYY'::text) AS date_inscription,
    to_char(c.derniere_connexion, 'DD/MM/YYYY'::text) AS derniere_connexion,
        CASE
            WHEN (c.role_actuel = ANY (ARRAY['DIRECTION'::public.role_utilisateur, 'SURVEILLANT'::public.role_utilisateur])) THEN adm.poste_occupe
            WHEN (c.role_actuel = 'PROFESSEUR'::public.role_utilisateur) THEN p.specialite
            WHEN (c.role_actuel = 'ELEVE'::public.role_utilisateur) THEN pe.classe_actuelle
            WHEN (c.role_actuel = 'PARENT'::public.role_utilisateur) THEN pp.profession
            ELSE NULL::character varying
        END AS info_specifique,
        CASE
            WHEN ((c.role_actuel = 'PARENT'::public.role_utilisateur) AND (b.id_membre IS NOT NULL)) THEN b.poste
            ELSE NULL::public.fonction_ape
        END AS role_ape
   FROM (((((authentification.comptes c
     LEFT JOIN authentification.profils_administratifs adm ON ((c.id_user = adm.id_user)))
     LEFT JOIN pedagogie.profils_profs p ON ((c.id_user = p.id_user)))
     LEFT JOIN vie_scolaire.profils_eleves pe ON ((c.id_user = pe.id_user)))
     LEFT JOIN gestion_ape.profils_parents pp ON ((c.id_user = pp.id_user)))
     LEFT JOIN gestion_ape.bureau_direction b ON ((pp.id_parent = b.id_parent)))
  WHERE (c.role_actuel = ANY (ARRAY['DIRECTION'::public.role_utilisateur, 'SURVEILLANT'::public.role_utilisateur, 'PROFESSEUR'::public.role_utilisateur, 'ELEVE'::public.role_utilisateur, 'PARENT'::public.role_utilisateur, 'ALUMNI'::public.role_utilisateur]));


ALTER VIEW public.vue_utilisateurs_unifiee OWNER TO postgres;

